def fib(n: int, memo: dict = None) -> int:
    # Initialize the memo dictionary on the first call
    if memo is None:
        memo = {0: 0, 1: 1}

    # Check if the value is already in our cache
    if n in memo:
        return memo[n]

    # Recursive step: compute and store the result in the dictionary
    memo[n] = fib(n - 1, memo) + fib(n - 2, memo)
    return memo[n]

